import{_ as e,c as d,o as a,a8 as o}from"./chunks/framework.BrmF0WDH.js";const b=JSON.parse('{"title":"Editor 编辑器原理","description":"","frontmatter":{},"headers":[],"relativePath":"theory/editor.md","filePath":"theory/editor.md","lastUpdated":1777649372000}'),r={name:"theory/editor.md"};function c(i,t,n,s,l,h){return a(),d("div",null,t[0]||(t[0]=[o(`<h1 id="editor-编辑器原理" tabindex="1">Editor 编辑器原理 <a class="header-anchor" href="#editor-编辑器原理" aria-label="Permalink to &quot;Editor 编辑器原理&quot;">​</a></h1><p><code>@quantum-lowcode/editor</code> 是可视化搭建的入口包。它不直接渲染业务组件，而是维护编辑器状态、节点树、属性面板、数据源面板和 Sandbox 画布之间的协作。</p><h2 id="关键职责" tabindex="1">关键职责 <a class="header-anchor" href="#关键职责" aria-label="Permalink to &quot;关键职责&quot;">​</a></h2><table tabindex="0"><thead><tr><th>职责</th><th>说明</th></tr></thead><tbody><tr><td>Schema 编辑</td><td>维护根 Schema、当前页面、当前选中节点</td></tr><tr><td>节点操作</td><td>提供新增、更新、删除、复制、粘贴、排序、拖拽等能力</td></tr><tr><td>画布协作</td><td>接收 Sandbox 的选择、拖拽、删除、参考线等事件</td></tr><tr><td>面板配置</td><td>根据节点类型展示属性表单和事件配置</td></tr><tr><td>历史记录</td><td>将关键节点操作写入历史栈，支持撤销和重做</td></tr><tr><td>数据源配置</td><td>管理根 Schema 上的 <code>dataSources</code></td></tr></tbody></table><h2 id="服务结构" tabindex="1">服务结构 <a class="header-anchor" href="#服务结构" aria-label="Permalink to &quot;服务结构&quot;">​</a></h2><p>编辑器内部将能力拆成多个 service：</p><table tabindex="0"><thead><tr><th>Service</th><th>主要职责</th></tr></thead><tbody><tr><td><code>EditorService</code></td><td>节点树增删改查、选中、高亮、复制粘贴、拖拽排序</td></tr><tr><td><code>UiService</code></td><td>画布尺寸、缩放、布局类 UI 状态</td></tr><tr><td><code>PropsService</code></td><td>属性面板值、属性表单配置和字段名变更</td></tr><tr><td><code>DataSourceService</code></td><td>数据源列表的新增、更新、删除和读取</td></tr><tr><td><code>HistoryService</code></td><td>操作历史、撤销、重做</td></tr><tr><td><code>ComponentService</code></td><td>左侧组件物料分组和组件默认配置</td></tr><tr><td><code>ContentmenuService</code></td><td>右键菜单和扩展操作</td></tr></tbody></table><p>这些服务通过 <code>use-service</code> 初始化，并在编辑器组件树中共享。</p><h2 id="节点更新链路" tabindex="1">节点更新链路 <a class="header-anchor" href="#节点更新链路" aria-label="Permalink to &quot;节点更新链路&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>属性面板修改</span></span>
<span class="line"><span>  -&gt; PropsService 产出局部配置</span></span>
<span class="line"><span>  -&gt; EditorService.update/updateHelper 合并节点</span></span>
<span class="line"><span>  -&gt; root Schema 被更新</span></span>
<span class="line"><span>  -&gt; Sandbox 接收更新并同步 iframe</span></span>
<span class="line"><span>  -&gt; Runtime 重新渲染对应节点</span></span></code></pre></div><p>新增节点时，<code>EditorService.add</code> 会先确定父节点和插入位置，再修正节点 <code>field</code>，最后同步画布。删除、复制、粘贴和排序也都围绕根 Schema 的树操作完成。</p><h2 id="画布事件协作" tabindex="1">画布事件协作 <a class="header-anchor" href="#画布事件协作" aria-label="Permalink to &quot;画布事件协作&quot;">​</a></h2><p>Sandbox 负责真实 DOM 的选择和拖拽，编辑器负责把交互结果落回 Schema。</p><table tabindex="0"><thead><tr><th>Sandbox 事件</th><th>Editor 处理</th></tr></thead><tbody><tr><td>选中节点</td><td><code>EditorService.select</code></td></tr><tr><td>hover 高亮</td><td><code>EditorService.highlight</code></td></tr><tr><td>拖拽更新</td><td><code>EditorService.update</code> 写入 <code>style</code></td></tr><tr><td>删除节点</td><td><code>EditorService.delete</code></td></tr><tr><td>拖到容器</td><td><code>EditorService.dragTo</code> 或 <code>moveToContainer</code></td></tr></tbody></table><h2 id="属性面板如何动态生成" tabindex="1">属性面板如何动态生成 <a class="header-anchor" href="#属性面板如何动态生成" aria-label="Permalink to &quot;属性面板如何动态生成&quot;">​</a></h2><p>组件的属性表单配置来自 <code>propsConfigs</code>，默认值来自 <code>propsValues</code>。编辑器根据当前节点的 <code>component</code> 或 <code>type</code> 找到对应配置，然后把表单结果转成节点上的 <code>componentProps</code>、<code>style</code> 等字段。</p><p>这也是扩展组件时最常见的接入点：注册组件、补充物料信息、补充属性面板配置。</p><h2 id="容易踩坑的点" tabindex="1">容易踩坑的点 <a class="header-anchor" href="#容易踩坑的点" aria-label="Permalink to &quot;容易踩坑的点&quot;">​</a></h2><ul><li>只更新 iframe DOM，不更新 Schema：刷新或切页后会丢失。</li><li>只更新 Schema，不通知 Sandbox：画布选框和实际 DOM 会短暂不一致。</li><li>复制节点时没有重写 <code>field</code>：节点表会被覆盖，选中和更新都会异常。</li><li>自定义容器没有被 <code>isContainer</code> 识别：节点无法拖入该容器。</li></ul><h2 id="调试入口" tabindex="1">调试入口 <a class="header-anchor" href="#调试入口" aria-label="Permalink to &quot;调试入口&quot;">​</a></h2><ul><li>节点结构问题：先看 <code>EditorService.getNodeInfo(field)</code>。</li><li>属性不生效：检查节点最终的 <code>componentProps</code> 和 <code>style</code>。</li><li>画布错位：检查 Sandbox 返回的拖拽数据和节点 <code>style</code>。</li><li>数据源不更新：检查根 Schema 的 <code>dataSources</code> 和表达式依赖。</li></ul>`,21)]))}const u=e(r,[["render",c]]);export{b as __pageData,u as default};
